import uuid
from flask import Flask, request, jsonify
import os, json
from groq import Groq
from dotenv import load_dotenv
app = Flask(__name__)

load_dotenv()
client = Groq(api_key=os.environ.get("GROQ_API_KEY"))

def llm_signal(text):
    prompt = (
        "You are an AI-text detector. Assess whether the following text was "
        "written by a human or generated by AI. Respond with ONLY a JSON object "
        'of the form {"ai_likelihood": <number between 0 and 1>}, where 1 means '
        "definitely AI-generated and 0 means definitely human-written.\n\n"
        f"TEXT:\n{text}"
    )
    response = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=[{"role": "user", "content": prompt}],
        temperature=0,
    )
    raw = response.choices[0].message.content
    result = json.loads(raw)
    return float(result["ai_likelihood"])
@app.route("/submit", methods=["POST"])
def submit():
    data = request.get_json()
    text = data.get("text")
    creator_id = data.get("creator_id")

    # Hardcoded for now — we'll wire in the Groq signal next step.
    return jsonify({
        "content_id": str(uuid.uuid4()),
        "attribution": "uncertain",
        "confidence": 0.5,
        "label": "placeholder label",
    })

if __name__ == "__main__":
    app.run(port=5001, debug=True)
    print("human-ish:", llm_signal("ugh my code broke again, third time today lol"))
    print("ai-ish:", llm_signal("Furthermore, it is important to note that effective time management significantly enhances overall productivity."))